class DeepLinkRouter {
  static Route<dynamic>? handleDeepLink(Uri uri, BuildContext context) {
    final host = uri.host.toLowerCase();
    final pathSegments = uri.pathSegments;
    final queryParams = uri.queryParameters;

    switch (host) {
      case 'profile':
        return _handleProfileRoute(pathSegments, queryParams);
      case 'payment':
        return _handlePaymentRoute(pathSegments, queryParams);
      case 'product':
        return _handleProductRoute(pathSegments, queryParams);
      case 'settings':
        return _handleSettingsRoute(pathSegments, queryParams);
      default:
        return null;
    }
  }

  static Route<dynamic>? _handleProfileRoute(
    List<String> pathSegments,
    Map<String, String> queryParams,
  ) {
    if (pathSegments.isEmpty) {
      return MaterialPageRoute(
        builder: (_) => const ProfileScreen(),
      );
    }

    final userId = _sanitizeInput(pathSegments[0]);
    if (userId != null && _isValidUserId(userId)) {
      return MaterialPageRoute(
        builder: (_) => ProfileScreen(userId: userId),
      );
    }

    return null;
  }

  static Route<dynamic>? _handlePaymentRoute(
    List<String> pathSegments,
    Map<String, String> queryParams,
  ) {
    if (pathSegments.isEmpty) {
      return null;
    }

    final action = _sanitizeInput(pathSegments[0]);
    
    if (action == 'confirm') {
      final transactionId = _sanitizeInput(queryParams['transaction_id']);
      final amount = _sanitizeInput(queryParams['amount']);
      
      if (transactionId != null && 
          amount != null && 
          _isValidTransactionId(transactionId) &&
          _isValidAmount(amount)) {
        return MaterialPageRoute(
          builder: (_) => PaymentConfirmScreen(
            transactionId: transactionId,
            amount: amount,
          ),
        );
      }
    } else if (action == 'history') {
      return MaterialPageRoute(
        builder: (_) => const PaymentHistoryScreen(),
      );
    }

    return null;
  }

  static Route<dynamic>? _handleProductRoute(
    List<String> pathSegments,
    Map<String, String> queryParams,
  ) {
    if (pathSegments.isEmpty) {
      return MaterialPageRoute(
        builder: (_) => const ProductListScreen(),
      );
    }

    final productId = _sanitizeInput(pathSegments[0]);
    if (productId != null && _isValidProductId(productId)) {
      final category = _sanitizeInput(queryParams['category']);
      return MaterialPageRoute(
        builder: (_) => ProductDetailScreen(
          productId: productId,
          category: category,
        ),
      );
    }

    return null;
  }

  static Route<dynamic>? _handleSettingsRoute(
    List<String> pathSegments,
    Map<String, String> queryParams,
  ) {
    if (pathSegments.isEmpty) {
      return MaterialPageRoute(
        builder: (_) => const SettingsScreen(),
      );
    }

    final section = _sanitizeInput(pathSegments[0]);
    if (section != null) {
      return MaterialPageRoute(
        builder: (_) => SettingsScreen(section: section),
      );
    }

    return null;
  }

  static String? _sanitizeInput(String? input) {
    if (input == null || input.isEmpty) return null;
    
    final sanitized = input
        .replaceAll(RegExp(r'[<>"\']'), '')
        .replaceAll(RegExp(r'[\x00-\x1F\x7F]'), '')
        .trim();
    
    return sanitized.isEmpty ? null : sanitized;
  }

  static bool _isValidUserId(String userId) {
    return RegExp(r'^\d+$').hasMatch(userId) && userId.length <= 20;
  }

  static bool _isValidTransactionId(String transactionId) {
    return RegExp(r'^[a-zA-Z0-9_-]+$').hasMatch(transactionId) && 
           transactionId.length <= 50;
  }

  static bool _isValidAmount(String amount) {
    final parsed = double.tryParse(amount);
    return parsed != null && parsed >= 0 && parsed <= 1000000;
  }

  static bool _isValidProductId(String productId) {
    return RegExp(r'^[a-zA-Z0-9_-]+$').hasMatch(productId) && 
           productId.length <= 30;
  }
}

class DeepLinkNavigator extends StatefulWidget {
  final Widget child;

  const DeepLinkNavigator({Key? key, required this.child}) : super(key: key);

  @override
  State<DeepLinkNavigator> createState() => _DeepLinkNavigatorState();
}

class _DeepLinkNavigatorState extends State<DeepLinkNavigator> {
  final DeepLinkHandler _deepLinkHandler = DeepLinkHandler();
  StreamSubscription? _deepLinkSubscription;

  @override
  void initState() {
    super.initState();
    _deepLinkHandler.initialize();
    _deepLinkSubscription = _deepLinkHandler.deepLinkStream.listen(_onDeepLink);
  }

  void _onDeepLink(Uri uri) {
    if (!mounted) return;

    final route = DeepLinkRouter.handleDeepLink(uri, context);
    if (route != null) {
      Navigator.of(context).push(route);
    } else {
      _showInvalidLinkDialog();
    }
  }

  void _showInvalidLinkDialog() {
    showDialog(
      context: context,
      builder: (context) => AlertDialog(
        title: const Text('Invalid Link'),
        content: const Text('The link you followed is invalid or has expired.'),
        actions: [
          TextButton(
            onPressed: () => Navigator.of(context).pop(),
            child: const Text('OK'),
          ),
        ],
      ),
    );
  }

  @override
  void dispose() {
    _deepLinkSubscription?.cancel();
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    return widget.child;
  }
}

